sys_script.script:
(function executeRule(current, previous) {

    var utils = new IncentNowAccessUtils();
    var userId = gs.getUserID();

    // =========================================
    // BUSINESS GROUP EXECUTIVE
    // =========================================
    if (gs.hasRole('x_ctans_incentnow.business_group_executive')) {

        // Skip higher roles/managers if needed
        if (!utils.shouldSkipForPlanExe()) {
            utils.applyPlanBUFilter(current);
        }

        return;
    }
    // ORG EXECUTIVE - FULL ACCESS
    if (gs.hasRole('x_ctans_incentnow.org_executive')) {
        return;
    }

    // =========================================
    // APPLICATION ADMIN
    // =========================================
    if (gs.hasRole('x_ctans_incentnow.admin')) {
        return;
    }

    // =========================================
    // BUSINESS GROUP ADMIN / ADMIN
    // =========================================
    if (
        gs.hasRole('x_ctans_incentnow.business_group_admin')
    ) {

        // Skip higher roles
        if (!utils.shouldSkipForPlan()) {
            utils.applyPlanBUFilter(current);
        }

        return;
    }

    // =========================================
    // MANAGER
    // =========================================
    if (gs.hasRole('x_ctans_incentnow.manager')) {

        //var userIds = utils.getUserAndReportees(gs.getUserID());
        utils.applyManagerPlanFilter(current);
        return;
    }

    // =========================================
    // REPRESENTATIVE
    // =========================================
    if (gs.hasRole('x_ctans_incentnow.user')) {

        utils.applyPlanUserBasedFilter(current, [gs.getUserID()]);
        return;
    }

})(current, previous);
